        return max(abs(a[0] - b[0]), abs(a[1] - b[1]))

    my_pos = (sx, sy)
    op_pos = (ox, oy)

    # Intercept opponent's nearest resource if we can match or beat the contest distance.
    best_op = None
    best_opd = None
    for r in resources:
        d = cheb(op_pos, r)
        if best_opd is None or d < best_opd:
            best_opd = d
            best_op = r

